        logStyledMessage(`  Account ${index + 1}: ${account}`, 'success');
      });
      return accounts;
    } else {
      logStyledMessage('No accounts found or connected after request. User might have rejected or has no accounts.', 'warn');
      throw new Error('No accounts connected.');
