    const API_KEY_ENV_VAR = 'ZIRCUIT_API_KEY';
    const ENVIRONMENT_ENV_VAR = 'ZIRCUIT_ENVIRONMENT';
    const REQUEST_ID_HEADER = 'HTTP_X_ZIRCUIT_REQUEST_ID'; // Apache converts 'X-Zircuit-Request-ID' to 'HTTP_X_ZIRCUIT_REQUEST_ID'

